import os
import threading
import queue
import time
import logging
from flask import Flask, request, Response, send_file, abort
from werkzeug.utils import secure_filename

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mov', 'mkv'}
CHUNK_SIZE = 1024 * 1024  # 1MB chunk size
MAX_UPLOAD_SIZE = 1024 * 1024 * 1024  # 1GB max upload size

# Logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Create upload folder if it doesn't exist
if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_UPLOAD_SIZE

# Video metadata (in-memory for simplicity, consider a database for persistence)
video_metadata = {}  # {filename: {'resolutions': ['720p', '1080p'], 'duration': 120}}

# Transcoding queue (for handling different resolutions)
transcoding_queue = queue.Queue()

# Thread pool for transcoding
NUM_TRANSCODING_THREADS = 2

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def generate_chunks(filepath, start, end):
    """Generates video chunks for streaming."""
    with open(filepath, 'rb') as f:
        f.seek(start)
        bytes_to_read = end - start + 1
        while bytes_to_read > 0:
            chunk = f.read(min(CHUNK_SIZE, bytes_to_read))
            if not chunk:
                break
            bytes_to_read -= len(chunk)
            yield chunk

def transcode_video(filename, resolution):
    """Simulates video transcoding (replace with actual transcoding logic)."""
    logging.info(f"Starting transcoding of {filename} to {resolution}")
    time.sleep(5)  # Simulate transcoding time
    # In a real application, you would use ffmpeg or similar to transcode the video
    # and store the transcoded version in a separate file.
    # For example:
    # os.system(f"ffmpeg -i {os.path.join(UPLOAD_FOLDER, filename)} -vf scale={resolution} {os.path.join(UPLOAD_FOLDER, filename.split('.')[0] + '_' + resolution + '.mp4')}")
    logging.info(f"Finished transcoding of {filename} to {resolution}")
    # Update video metadata (in a real app, this would be in a database)
    if filename in video_metadata:
        video_metadata[filename]['resolutions'].append(resolution)
    else:
        video_metadata[filename] = {'resolutions': [resolution], 'duration': 60} #Dummy duration

def transcoding_worker():
    """Worker thread for handling transcoding tasks."""
    while True:
        try:
            filename, resolution = transcoding_queue.get(timeout=5)  # Timeout to allow graceful shutdown
            transcode_video(filename, resolution)
            transcoding_queue.task_done()
        except queue.Empty:
            logging.info("Transcoding worker exiting due to inactivity.")
            break
        except Exception as e:
            logging.error(f"Error during transcoding: {e}")
            transcoding_queue.task_done()

# Start transcoding worker threads
for _ in range(NUM_TRANSCODING_THREADS):
    threading.Thread(target=transcoding_worker, daemon=True).start()

@app.route('/upload', methods=['POST'])
def upload_file():
    """Handles video uploads."""
    if 'file' not in request.files:
        return 'No file part', 400
    file = request.files['file']
    if file.filename == '':
        return 'No selected file', 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        logging.info(f"File uploaded successfully: {filename}")

        # Add to transcoding queue (e.g., for 720p and 1080p)
        transcoding_queue.put((filename, '720p'))
        transcoding_queue.put((filename, '1080p'))

        return 'File uploaded successfully', 200
    return 'Invalid file type', 400

@app.route('/video/<filename>')
def stream_video(filename):
    """Streams video content."""
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
    if not os.path.exists(filepath):
        abort(404)

    range_header = request.headers.get('Range')
    if not range_header:
        # Serve the entire video if no range is specified
        return send_file(filepath, mimetype='video/mp4')

    try:
        start, end = parse_range_header(range_header)
    except ValueError:
        return 'Invalid range', 400

    file_size = os.path.getsize(filepath)
    end = min(end, file_size - 1)

    if start >= file_size or start > end:
        return 'Range Not Satisfiable', 416, {'Content-Range': f'bytes */{file_size}'}

    content_length = end - start + 1
    response = Response(
        generate_chunks(filepath, start, end),
        206,
        mimetype='video/mp4',
        content_type='video/mp4',
    )

    response.headers.add('Content-Range', f'bytes {start}-{end}/{file_size}')
    response.headers.add('Accept-Ranges', 'bytes')
    response.headers.add('Content-Length', content_length)
    return response

def parse_range_header(range_header):
    """Parses the Range header to extract start and end bytes."""
    parts = range_header.replace('bytes=', '').split('-')
    start = int(parts[0])
    end = int(parts[1]) if parts[1] else float('inf')
    return start, end

@app.route('/metadata/<filename>')
def get_video_metadata(filename):
    """Returns video metadata (resolutions, duration)."""
    if filename in video_metadata:
        return video_metadata[filename], 200
    else:
        return {'error': 'Metadata not found'}, 404

@app.route('/list')
def list_videos():
    """Lists available videos."""
    videos = [f for f in os.listdir(app.config['UPLOAD_FOLDER']) if allowed_file(f)]
    return {'videos': videos}, 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')

