import os
import threading
import time
from flask import Flask, render_template, request, Response, send_file
import cv2

app = Flask(__name__)

VIDEO_FOLDER = 'videos'  # Store videos in this folder
RESOLUTIONS = {
    '360p': (640, 360),
    '480p': (854, 480),
    '720p': (1280, 720),
    '1080p': (1920, 1080)
}

# Ensure video folder exists
if not os.path.exists(VIDEO_FOLDER):
    os.makedirs(VIDEO_FOLDER)

def get_video_list():
    """Returns a list of video files in the VIDEO_FOLDER."""
    video_files = [f for f in os.listdir(VIDEO_FOLDER) if f.endswith(('.mp4', '.avi', '.mov'))]
    return video_files

@app.route('/')
def index():
    """Renders the index page with a list of available videos."""
    videos = get_video_list()
    return render_template('index.html', videos=videos)

@app.route('/video/<filename>')
def video_page(filename):
    """Renders the video player page for a specific video."""
    return render_template('video.html', video_filename=filename, resolutions=list(RESOLUTIONS.keys()))

def generate_frames(filename, resolution):
    """Generates video frames for streaming."""
    video_path = os.path.join(VIDEO_FOLDER, filename)
    try:
        cap = cv2.VideoCapture(video_path)
        if not cap.isOpened():
            raise Exception(f"Could not open video: {video_path}")

        width, height = RESOLUTIONS.get(resolution, (640, 360))  # Default to 360p if resolution is invalid

        while True:
            ret, frame = cap.read()
            if not ret:
                break  # End of video

            # Resize the frame
            resized_frame = cv2.resize(frame, (width, height))

            # Encode the frame as JPEG
            _, buffer = cv2.imencode('.jpg', resized_frame, [int(cv2.IMWRITE_JPEG_QUALITY), 60])  # Adjust quality for bandwidth
            frame_bytes = buffer.tobytes()

            yield (b'--frame\r\n'
                   b'Content-Type: image/jpeg\r\n\r\n' + frame_bytes + b'\r\n')

        cap.release()
    except Exception as e:
        print(f"Error processing video: {e}")
    finally:
        cap.release()

@app.route('/stream/<filename>/<resolution>')
def stream_video(filename, resolution):
    """Streams the video using multipart/x-mixed-replace."""
    return Response(generate_frames(filename, resolution),
                    mimetype='multipart/x-mixed-replace; boundary=frame')

