class VideoPlayer:
    def __init__(self):
        self.video_url = None
        self.is_playing = False
        self.current_time = 0
        self.video_resolution = "720p"  # Default resolution
        self.video_size = "medium" # Default size
        self.video_quality = "good" # Default quality

    def load_video(self, video_url):
        """Loads a video from the given URL."""
        self.video_url = video_url
        print(f"Video loaded from: {video_url}")

    def play(self):
        """Starts playing the video."""
        if self.video_url:
            self.is_playing = True
            print("Playing video...")
        else:
            print("No video loaded. Please load a video first.")

    def pause(self):
        """Pauses the video."""
        if self.is_playing:
            self.is_playing = False
            print("Video paused.")
        else:
            print("Video is not playing.")

    def resume(self):
        """Resumes the video."""
        if not self.is_playing and self.video_url:
            self.is_playing = True
            print("Resuming video...")
        else:
            print("Video is already playing or no video loaded.")

    def seek(self, time):
        """Seeks to a specific time in the video (in seconds)."""
        if self.video_url:
            self.current_time = time
            print(f"Seeking to {time} seconds...")
        else:
            print("No video loaded.")

    def skip_forward(self, seconds):
        """Skips forward by a specified number of seconds."""
        if self.video_url:
            self.current_time += seconds
            print(f"Skipping forward {seconds} seconds...")
        else:
            print("No video loaded.")

    def skip_backward(self, seconds):
        """Skips backward by a specified number of seconds."""
        if self.video_url:
            self.current_time -= seconds
            print(f"Skipping backward {seconds} seconds...")
        else:
            print("No video loaded.")

    def set_resolution(self, resolution):
        """Sets the video resolution."""
        resolutions = ["144p", "240p", "360p", "480p", "720p", "1080p", "4k"]
        if resolution in resolutions:
            self.video_resolution = resolution
            print(f"Resolution set to {resolution}")
        else:
            print("Invalid resolution. Supported resolutions are:", resolutions)

    def set_size(self, size):
        """Sets the video size (small, medium, large)."""
        sizes = ["small", "medium", "large"]
        if size in sizes:
            self.video_size = size
            print(f"Size set to {size}")
        else:
            print("Invalid size. Supported sizes are:", sizes)

    def set_quality(self, quality):
        """Sets the video quality (bad, average, good, excellent)."""
        qualities = ["bad", "average", "good", "excellent"]
        if quality in qualities:
            self.video_quality = quality
